mapper.select:
/* com.educare.edu.comn.mapper.LectureRoomExcptMapper.selectByDt */
	select a.* 
	,(select room_nm from t_lecture_room where room_seq = a.room_seq) room_nm
	from t_lecture_room_excpt a
	where 1=1
	and (
		a.start_dt between #{startDt} and #{endDt}
		or a.end_dt between #{startDt} and #{endDt}
	)
